```ruby
class HashMap
  def initialize
    @keys = []
    @values = []
  end

  # Method to add a key-value pair to the hashmap
  def add(key, value)
    @keys << key
    @values << value
  end

  # Method to retrieve the value for a given key
  def get(key)
    index = @keys.find_index(key)
    return @values[index] if index
  end

  # Method to delete a key-value pair from the hashmap
  def delete(key)
    index = @keys.find_index(key)
    @keys.delete_at(index) if index
    @values.delete_at(index) if index
  end

  # Method to check if a given key exists in the hashmap
  def contains_key? (key)
    @keys.include? (key)
  end

  # Method to update the value for a given key
  def update(key, value)
    index = @keys.find_index(key)
    @values[index] = value if index
  end
end
```

